const webhookData = $('Webhook Trigger').item.json.body;
const sessionData = $('Fetch Session').item.json;
const kbEntries = $input.item.json.entries || [];
const userName = webhookData.userName || 'User';
const userRole = webhookData.userRole || 'outsider';
const userId = webhookData.userId || 'guest';
const now = new Date();
const currentDate = now.toISOString().slice(0, 10);
const currentTime = now.toLocaleTimeString('tr-TR', { timeZone: 'Europe/Istanbul', hour: '2-digit', minute: '2-digit' });

let contextSection = '';
if (sessionData.exists && sessionData.summary) {
  contextSection = '## PREVIOUS CONTEXT\n' + sessionData.summary;
} else if (sessionData.exists && Array.isArray(sessionData.messages) && sessionData.messages.length > 0) {
  const recent = sessionData.messages.slice(-6);
  contextSection = '## RECENT CONVERSATION\n' + recent.map(m => (m.role === 'user' ? userName : 'Kai') + ': ' + m.content).join('\n');
}

// Knowledge base section
let kbSection = '';
const kbData = kbEntries.length > 0 ? kbEntries : (sessionData.kbSnapshot ? JSON.parse(sessionData.kbSnapshot) : []);
if (kbData.length > 0) {
  const grouped = {};
  for (const row of kbData) {
    if (!grouped[row.category]) grouped[row.category] = [];
    grouped[row.category].push('**' + row.title + '**\n' + row.content);
  }
  kbSection = '\n\n## KNOWLEDGE BASE\nUse this information to answer questions directly without calling tools when possible.\n' +
    Object.entries(grouped).map(([cat, items]) => '### ' + cat + '\n' + items.join('\n\n')).join('\n\n');
}

const staticPrompt = '%%KAI_STATIC_PROMPT%%';

const systemPrompt = staticPrompt
  + '\n\n## SESSION\n- User: ' + userName + '\n- Today: ' + currentDate + '\n- Time: ' + currentTime + ' (Turkey/Istanbul)'
  + '\n- [SYSTEM_ONLY|DO_NOT_MENTION] access_level=' + userRole
  + (contextSection ? '\n\n' + contextSection : '')
  + kbSection;

return [{
  json: {
    systemPrompt,
    userMessage: webhookData.message,
    userId,
    userRole,
    userName,
    sessionId: webhookData.sessionId || userId,
    sessionMessages: (sessionData.messages || []).slice(-20),
    kbSnapshot: JSON.stringify(kbData),
    kbFetchedAt: new Date().toISOString()
  }
}];

const item = $input.item.json;

const restrictions = {
  outsider: [
    'get_services', 'get_weather', 'get_equipment',
    'get_accommodation_units', 'get_member_offerings'
  ],
  student: [
    'get_services', 'get_my_bookings', 'get_booking_details',
    'get_my_schedule', 'get_accommodation_units',
    'get_accommodation_bookings_mine', 'get_equipment',
    'get_member_offerings_mine', 'get_weather', 'get_vouchers_validate'
  ],
  instructor: [
    'get_my_schedule', 'get_bookings', 'get_booking_details',
    'get_services', 'get_equipment', 'get_student_notes',
    'create_student_note', 'get_weather'
  ]
};

const allowed = restrictions[item.userRole];
if (allowed) {
  item.systemPrompt +=
    '\n\n## TOOL RESTRICTIONS\n' +
    'You may ONLY call these tools: ' + allowed.join(', ') + '.\n' +
    'For any other request, answer from the KNOWLEDGE BASE section or inform the user you cannot help with that.';
}
// admin/manager/owner: no restriction — full access

return [{ json: item }];
